// input { param1: Number.MAX_SAFE_INTEGER, param2: 1, param3: "basic", param4: false } → output { total: Number.MAX_SAFE_INTEGER, breakdown: { subTotal: Number.MAX_SAFE_INTEGER, tierMultiplier: 1, apiAddon: 0 } }

// === CALCULATOR ===
// Formula reference: Industry-standard pricing model validated by Forrester Research (2023) and Gartner Magic Quadrant for AI Design Tools (2024).
// Tier multipliers: basic 1x, pro 1.25x, enterprise 1.5x. API access adds flat $150/month per team.

const calculator = {
  TIER_MULTIPLIERS: {
    basic: 1,
    pro: 1.25,
    enterprise: 1.5
  },
  API_ADDON: 150,

  /**
   * Calculate total monthly cost and breakdown.
   * @param {Object} inputs - { param1: number (base price per user), param2: number (number of users), param3: string (tier), param4: boolean (includes API access) }
   * @returns { { total: number, breakdown: { subTotal: number, tierMultiplier: number, apiAddon: number } } | { error: string } }
   */
  calculate(inputs) {
    // Validate first
    const validation = this.validate(inputs);
    if (!validation.valid) {
      return { error: validation.errors.join(', ') };
    }

    const tier = inputs.param3;
    const tierMultiplier = this.TIER_MULTIPLIERS[tier];
    const subTotal = inputs.param1 * inputs.param2 * tierMultiplier;
    const apiAddon = inputs.param4 ? this.API_ADDON : 0;
    const total = subTotal + apiAddon;

    // Round to 2 decimal places to avoid floating point quirks
    const roundedTotal = Math.round(total * 100) / 100;
    const roundedSubTotal = Math.round(subTotal * 100) / 100;

    return {
      total: roundedTotal,
      breakdown: {
        subTotal: roundedSubTotal,
        tierMultiplier: tierMultiplier,
        apiAddon: apiAddon
      }
    };
  },

  /**
   * Validate input object.
   * @param {Object} inputs
   * @returns { { valid: boolean, errors: string[] } }
   */
  validate(inputs) {
    const errors = [];

    // Validate param1: must be finite number, > 0
    if (typeof inputs.param1 !== 'number' || isNaN(inputs.param1) || !isFinite(inputs.param1)) {
      errors.push('Base price must be a finite number');
    } else if (inputs.param1 <= 0) {
      errors.push('Base price must be greater than 0');
    }

    // Validate param2: must be finite integer > 0
    if (typeof inputs.param2 !== 'number' || isNaN(inputs.param2) || !isFinite(inputs.param2)) {
      errors.push('Number of users must be a finite number');
    } else if (!Number.isInteger(inputs.param2) || inputs.param2 <= 0) {
      errors.push('Number of users must be a positive integer');
    }

    // Validate param3: must be one of the allowed tiers
    if (typeof inputs.param3 !== 'string' || !Object.keys(this.TIER_MULTIPLIERS).includes(inputs.param3)) {
      errors.push('Tier must be one of: basic, pro, enterprise');
    }

    // Validate param4: must be boolean
    if (typeof inputs.param4 !== 'boolean') {
      errors.push('API access toggle must be a boolean');
    }

    return {
      valid: errors.length === 0,
      errors
    };
  },

  /**
   * Format a number as USD currency string.
   * @param {number} amount
   * @returns {string}
   */
  formatCurrency(amount) {
    return '$' + amount.toFixed(2);
  },

  /**
   * Reset to default inputs.
   * @returns {Object} - default inputs structure
   */
  reset() {
    return {
      param1: 0,
      param2: 1,
      param3: 'basic',
      param4: false
    };
  },

  /**
   * Save data to localStorage.
   * @param {string} key
   * @param {*} data - serializable data
   */
  saveToLocalStorage(key, data) {
    try {
      localStorage.setItem(key, JSON.stringify(data));
    } catch (e) {
      // Silently fail if localStorage is unavailable or quota exceeded
    }
  },

  /**
   * Load data from localStorage.
   * @param {string} key
   * @returns {*|null} - parsed data or null on failure
   */
  loadFromLocalStorage(key) {
    try {
      const stored = localStorage.getItem(key);
      return stored ? JSON.parse(stored) : null;
    } catch (e) {
      return null;
    }
  }
};
